import { useState, useEffect, useCallback, useRef } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Polyline, useMap } from 'react-leaflet';
import toast from 'react-hot-toast';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import useDeliveryStore from '../store/deliveryStore';
import useAuthStore from '../store/authStore';

// ----- Leaflet Icon Fix for Vite -----
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

// ----- Custom Icons -----
const createIcon = (color) => new L.Icon({
  iconUrl: `https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-${color}.png`,
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
  iconSize: [25, 41], iconAnchor: [12, 41], popupAnchor: [1, -34], shadowSize: [41, 41],
});
const pickupIcon  = createIcon('orange');
const dropoffIcon = createIcon('green');

// Pulsing truck icon for the live delivery tracker
const truckIcon = L.divIcon({
  className: '',
  html: `<div style="
    width:44px; height:44px; border-radius:50%;
    background: rgba(249,115,22,0.2);
    border: 3px solid #f97316;
    display:flex; align-items:center; justify-content:center;
    box-shadow: 0 0 0 0 rgba(249,115,22,0.7);
    animation: trackerPulse 1.6s infinite;
    font-size:20px; line-height:1;
  ">­ƒÜÜ</div>`,
  iconSize: [44, 44],
  iconAnchor: [22, 22],
  popupAnchor: [0, -22],
});

// ----- Inner component that has access to map instance -----
function MapController({ flyTarget, zoomCmd }) {
  const map = useMap();
  useEffect(() => {
    if (zoomCmd === 'in')  map.zoomIn();
    if (zoomCmd === 'out') map.zoomOut();
  }, [zoomCmd, map]);
  useEffect(() => {
    if (flyTarget) map.flyTo(flyTarget, 15, { animate: true, duration: 1.2 });
  }, [flyTarget, map]);
  return null;
}

// Forces Leaflet to recalculate tile grid when container is resized/remounted
function MapResizer() {
  const map = useMap();
  useEffect(() => {
    // Small delay lets the flexbox layout settle before we invalidate
    const t = setTimeout(() => {
      map.invalidateSize({ animate: false });
    }, 100);
    return () => clearTimeout(t);
  }, [map]);
  return null;
}

// ----- Static fallback route (shown when no Appwrite delivery is live) -----
const DEMO_ROUTE = {
  pickup:  { lat: 20.2961, lng: 85.8245, name: 'City Hospital Canteen',  address: '123 Hospital Rd, Bhubaneswar' },
  dropoff: { lat: 20.2858, lng: 85.8361, name: 'Hope Orphanage',          address: '45 Chilika Colony, Bhubaneswar' },
};
const DEFAULT_CENTER = [20.2910, 85.8300];

// ----- Helpers -----

function fmtDur(seconds) {
  if (!seconds) return 'ÔÇö';
  const m = Math.round(seconds / 60);
  if (m < 60) return `${m} min`;
  return `${Math.floor(m / 60)}h ${m % 60}m`;
}
function fmtSpeed(mps) {
  // mps = metres per second from Geolocation API
  if (!mps || mps < 0) return '0';
  return Math.round(mps * 3.6).toFixed(0); // convert to km/h
}

// ----- Mobile-friendly Delivery Card (collapsed pill on mobile, full on desktop) -----
function MobileDeliveryCard({ isLoading, activeRoute, distKm, routeDuration, displaySpeed, tracking, startTracking, stopTracking, fmtDur }) {
  const [expanded, setExpanded] = useState(false);

  if (isLoading) {
    return (
      <div className="absolute bottom-4 left-4 right-4 md:bottom-8 md:left-8 md:right-auto md:w-80 bg-[#281e1b]/95 backdrop-blur-md p-3 md:p-4 rounded-xl shadow-2xl border border-[#3a2c27] z-10">
        <div className="flex items-center gap-2 text-[#bca39a] text-sm animate-pulse">
          <span className="material-symbols-outlined text-sm">sync</span> Loading live missionÔÇª
        </div>
      </div>
    );
  }

  return (
    <div className="absolute bottom-4 left-4 right-4 md:bottom-8 md:left-8 md:right-auto md:w-80 z-10">
      {/* ÔöÇÔöÇ Mobile: Compact pill (tap to expand) ÔöÇÔöÇ */}
      <div
        className={`md:hidden bg-[#281e1b]/95 backdrop-blur-md rounded-xl shadow-2xl border border-[#3a2c27] transition-all duration-300 overflow-hidden ${expanded ? 'p-4' : 'p-3 cursor-pointer'}`}
        onClick={() => !expanded && setExpanded(true)}
      >
        {!expanded ? (
          /* Collapsed: slim one-liner */
          <div className="flex items-center gap-3">
            <div className="bg-primary/20 p-1.5 rounded-lg text-primary shrink-0">
              <span className="material-symbols-outlined text-[18px]">local_shipping</span>
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-white text-xs font-bold truncate">{activeRoute.pickup.name} Ô×ö {activeRoute.dropoff.name}</p>
            </div>
            <div className="flex items-center gap-2 shrink-0">
              {distKm && <span className="text-orange-400 text-xs font-bold">{distKm} km</span>}
              <span className="material-symbols-outlined text-[#bca39a] text-[16px]">expand_less</span>
            </div>
          </div>
        ) : (
          /* Expanded: full card with collapse button */
          <>
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-3">
                <div className="bg-primary/20 p-2 rounded-lg text-primary shrink-0">
                  <span className="material-symbols-outlined">local_shipping</span>
                </div>
                <div>
                  <h4 className="text-white font-bold text-sm">Active Delivery</h4>
                  <p className="text-[#bca39a] text-xs truncate">{activeRoute.pickup.name} Ô×ö {activeRoute.dropoff.name}</p>
                </div>
              </div>
              <button onClick={(e) => { e.stopPropagation(); setExpanded(false); }} className="text-[#bca39a] hover:text-white p-1">
                <span className="material-symbols-outlined text-[18px]">expand_more</span>
              </button>
            </div>
            <DeliveryCardBody {...{ activeRoute, distKm, routeDuration, displaySpeed, tracking, startTracking, stopTracking, fmtDur }} />
          </>
        )}
      </div>

      {/* ÔöÇÔöÇ Desktop: Always full card ÔöÇÔöÇ */}
      <div className="hidden md:block bg-[#281e1b]/95 backdrop-blur-md p-4 rounded-xl shadow-2xl border border-[#3a2c27]">
        <div className="flex items-start gap-3 mb-3">
          <div className="bg-primary/20 p-2 rounded-lg text-primary shrink-0">
            <span className="material-symbols-outlined">local_shipping</span>
          </div>
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 mb-0.5">
              <h4 className="text-white font-bold text-sm">Active Delivery</h4>
              {activeRoute.status && (
                <span className="bg-orange-500/15 text-orange-400 text-[10px] font-bold px-1.5 py-0.5 rounded-full uppercase">
                  {activeRoute.status}
                </span>
              )}
            </div>
            <p className="text-[#bca39a] text-xs truncate">{activeRoute.pickup.name} Ô×ö {activeRoute.dropoff.name}</p>
          </div>
        </div>
        <DeliveryCardBody {...{ activeRoute, distKm, routeDuration, displaySpeed, tracking, startTracking, stopTracking, fmtDur }} />
      </div>
    </div>
  );
}

// Shared card body (stats + tracking button + pickup code)
function DeliveryCardBody({ activeRoute, distKm, routeDuration, displaySpeed, tracking, startTracking, stopTracking, fmtDur }) {
  return (
    <>
      <div className="grid grid-cols-3 gap-2">
        <div className="bg-[#3a2c27] rounded-lg p-2 text-center">
          <p className="text-white font-black text-sm">{distKm ?? 'ÔÇª'}</p>
          <p className="text-[#bca39a] text-[10px] uppercase tracking-wide font-medium mt-0.5">km</p>
        </div>
        <div className="bg-[#3a2c27] rounded-lg p-2 text-center">
          <p className="text-white font-black text-sm">{fmtDur(routeDuration)}</p>
          <p className="text-[#bca39a] text-[10px] uppercase tracking-wide font-medium mt-0.5">ETA</p>
        </div>
        <div className={`rounded-lg p-2 text-center ${tracking ? 'bg-orange-500/10 border border-orange-500/30' : 'bg-[#3a2c27]'}`}>
          <p className={`font-black text-sm ${tracking ? 'text-orange-400' : 'text-white'}`}>{displaySpeed}</p>
          <p className={`text-[10px] uppercase tracking-wide font-medium mt-0.5 ${tracking ? 'text-orange-400' : 'text-[#bca39a]'}`}>km/h</p>
        </div>
      </div>
      {!tracking ? (
        <button onClick={startTracking} className="mt-3 w-full flex items-center justify-center gap-2 bg-primary hover:bg-orange-700 text-white font-bold text-xs py-2 rounded-lg transition-all">
          <span className="material-symbols-outlined text-[16px]">radio_button_checked</span>
          Start Live Tracking
        </button>
      ) : (
        <div className="mt-3 flex items-center gap-2">
          <div className="flex-1 flex items-center gap-1.5 bg-orange-500/10 border border-orange-500/30 rounded-lg px-3 py-2">
            <span className="size-2 rounded-full bg-orange-500 animate-pulse" />
            <span className="text-orange-400 text-xs font-bold">LIVE</span>
            <span className="text-[#bca39a] text-xs ml-1">Tracking active</span>
          </div>
          <button onClick={stopTracking} className="p-2 rounded-lg bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 transition-colors">
            <span className="material-symbols-outlined text-[16px]">stop</span>
          </button>
        </div>
      )}
      {activeRoute.pickupCode && (
        <div className="mt-2 flex items-center gap-2">
          <span className="text-[#bca39a] text-xs">Pickup PIN:</span>
          <span className="ml-auto bg-[#3a2c27] text-[#bca39a] font-mono text-xs px-2 py-0.5 rounded font-bold">{activeRoute.pickupCode}</span>
        </div>
      )}
    </>
  );
}

// ----- Main Component -----
export default function InteractiveMap() {
  const { deliveries, fetchDeliveries, isLoading } = useDeliveryStore();
  const { user } = useAuthStore();

  // Map controls
  const [flyTarget, setFlyTarget] = useState(null);
  const [zoomCmd,   setZoomCmd]   = useState(null);

  // Active route
  const [activeRoute, setActiveRoute] = useState(DEMO_ROUTE);

  // Road-following route geometry + OSRM metadata
  const [routePositions, setRoutePositions] = useState([]);
  const [routeLoading, setRouteLoading]     = useState(false);
  const [routeDistance, setRouteDistance]   = useState(null); // metres
  const [routeDuration, setRouteDuration]   = useState(null); // seconds
  const routeAbort = useRef(null);

  // Live GPS tracker for the delivery person
  const [trackerPos, setTrackerPos]     = useState(null);  // [lat, lng]
  const [trackerSpeed, setTrackerSpeed] = useState(null);  // m/s from Geolocation
  const [tracking, setTracking]         = useState(false);
  const watchId = useRef(null);

  // Simulated speed (increments while tracking on desktop where speed is null)
  const [simSpeed, setSimSpeed]         = useState(0);
  const simRef = useRef(null);

  // Vehicle-to-pickup approach route
  const [approachRoute, setApproachRoute] = useState([]);
  const approachAbort = useRef(null);

  // ----- Fetch real deliveries from Appwrite on mount -----
  useEffect(() => {
    if (user) fetchDeliveries(user.$id).catch(() => {});
  }, [user, fetchDeliveries]);

  // Use the first live delivery from Appwrite if one exists
  useEffect(() => {
    if (deliveries?.length > 0) {
      const live = deliveries[0];
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setActiveRoute({
        pickup:  { lat: 20.2961, lng: 85.8245, name: live.requestId ? `Pickup #${live.requestId.slice(-6)}` : DEMO_ROUTE.pickup.name, address: 'Live Pickup Location' },
        dropoff: { lat: 20.2858, lng: 85.8361, name: live.volunteerName ? `Delivery by ${live.volunteerName}` : DEMO_ROUTE.dropoff.name, address: 'Live Dropoff Location' },
        status: live.status, pickupCode: live.pickupCode,
      });
    }
  }, [deliveries]);

  // ----- Fetch OSRM route whenever activeRoute changes -----
  useEffect(() => {
    const { pickup, dropoff } = activeRoute;
    if (!pickup?.lat || !dropoff?.lat) return;

    if (routeAbort.current) routeAbort.current.abort();
    const controller = new AbortController();
    routeAbort.current = controller;

    // eslint-disable-next-line react-hooks/set-state-in-effect
    setRouteLoading(true);
    // Clear previous route ÔÇö do NOT set a straight line here
    setRoutePositions([]);
    setRouteDistance(null);
    setRouteDuration(null);

    const url =
      `https://router.project-osrm.org/route/v1/driving/` +
      `${pickup.lng},${pickup.lat};${dropoff.lng},${dropoff.lat}` +
      `?overview=full&geometries=geojson`;

    fetch(url, { signal: controller.signal })
      .then(r => r.json())
      .then(data => {
        const route = data?.routes?.[0];
        if (route?.geometry?.coordinates?.length > 0) {
          setRoutePositions(route.geometry.coordinates.map(([lng, lat]) => [lat, lng]));
        } else {
          // OSRM returned no geometry ÔÇö fall back to straight line
          setRoutePositions([[pickup.lat, pickup.lng], [dropoff.lat, dropoff.lng]]);
        }
        setRouteDistance(route?.distance ?? null);
        setRouteDuration(route?.duration ?? null);
        setRouteLoading(false);
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          console.warn('OSRM failed, using straight line:', err.message);
          // Fall back to straight line on network error
          setRoutePositions([[pickup.lat, pickup.lng], [dropoff.lat, dropoff.lng]]);
        }
        setRouteLoading(false);
      });

    return () => controller.abort();
  }, [activeRoute]);

  // ----- Start / Stop live GPS tracking -----
  const stopTracking = useCallback(() => {
    if (watchId.current !== null) {
      navigator.geolocation.clearWatch(watchId.current);
      watchId.current = null;
    }
    clearInterval(simRef.current);
    setTracking(false);
    setSimSpeed(0);
    toast('Tracking stopped.', { icon: 'ÔÅ╣' });
  }, []);

  const startTracking = useCallback(() => {
    if (!navigator.geolocation) {
      toast.error('Geolocation not supported.'); return;
    }
    setTracking(true);
    toast.success('Live tracking started! ­ƒÜÜ');

    // Start a simulated speed ramp for desktop (no real GPS speed on desktop)
    let s = 10;
    simRef.current = setInterval(() => {
      s = Math.min(60, s + (Math.random() * 4 - 1));  // random walk 10-60 km/h
      setSimSpeed(s);
    }, 1000);

    watchId.current = navigator.geolocation.watchPosition(
      (pos) => {
        const { latitude, longitude, speed } = pos.coords;
        setTrackerPos([latitude, longitude]);
        setFlyTarget([latitude, longitude]);
        if (speed !== null) {
          setTrackerSpeed(speed);     // real m/s
          setSimSpeed(null);          // if real speed available, drop sim
        }
      },
      (err) => { toast.error(`Tracking error: ${err.message}`); stopTracking(); },
      { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
    );
  }, [stopTracking]);

  // Cleanup on unmount
  useEffect(() => () => {
    if (watchId.current !== null) navigator.geolocation.clearWatch(watchId.current);
    clearInterval(simRef.current);
    if (approachAbort.current) approachAbort.current.abort();
  }, []);

  // ----- Fetch approach route (vehicle ÔåÆ pickup) when tracking -----
  useEffect(() => {
    if (!tracking || !trackerPos) {
      setApproachRoute([]);
      return;
    }
    const { pickup } = activeRoute;
    if (!pickup?.lat) return;

    if (approachAbort.current) approachAbort.current.abort();
    const controller = new AbortController();
    approachAbort.current = controller;

    const url =
      `https://router.project-osrm.org/route/v1/driving/` +
      `${trackerPos[1]},${trackerPos[0]};${pickup.lng},${pickup.lat}` +
      `?overview=full&geometries=geojson`;

    fetch(url, { signal: controller.signal })
      .then(r => r.json())
      .then(data => {
        const route = data?.routes?.[0];
        if (route?.geometry?.coordinates?.length > 0) {
          setApproachRoute(route.geometry.coordinates.map(([lng, lat]) => [lat, lng]));
        } else {
          setApproachRoute([trackerPos, [pickup.lat, pickup.lng]]);
        }
      })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setApproachRoute([trackerPos, [pickup.lat, pickup.lng]]);
        }
      });

    return () => controller.abort();
  }, [tracking, trackerPos, activeRoute]);

  // ----- One-shot "Locate Me" -----
  const [locating, setLocating] = useState(false);
  const handleLocateMe = useCallback(() => {
    if (!navigator.geolocation) { toast.error('Geolocation not supported.'); return; }
    setLocating(true);
    const tid = toast.loading('Acquiring GPS signalÔÇª');
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const c = [pos.coords.latitude, pos.coords.longitude];
        setTrackerPos(c); setFlyTarget(c);
        toast.success('Located!', { id: tid });
        setLocating(false);
      },
      (err) => { toast.error(err.message, { id: tid }); setLocating(false); },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  }, []);

  // Speed to display (real GPS speed if available, else simulated)
  const displaySpeed = trackerSpeed !== null
    ? fmtSpeed(trackerSpeed)
    : simSpeed !== null && tracking
      ? Math.round(simSpeed).toFixed(0)
      : '0';

  // Polyline style
  const polylineOpts = routeLoading
    ? { color: '#f97316', weight: 3, opacity: 0.5, dashArray: '8, 8' }
    : { color: '#f97316', weight: 5, opacity: 0.9, lineCap: 'round', lineJoin: 'round' };

  // Distance remaining (crude: if tracking, subtract ~1km per 2 min elapsed ÔÇö demo)
  const distKm = routeDistance ? (routeDistance / 1000).toFixed(1) : null;

  return (
    <div className="relative w-full h-full bg-[#181210]">

      {/* ÔöÇÔöÇ Pulse keyframe ÔöÇÔöÇ */}
      <style>{`
        @keyframes trackerPulse {
          0%   { box-shadow: 0 0 0 0 rgba(249,115,22,0.7); }
          70%  { box-shadow: 0 0 0 16px rgba(249,115,22,0); }
          100% { box-shadow: 0 0 0 0 rgba(249,115,22,0); }
        }
        .leaflet-container { background-color: #181210 !important; }
        .leaflet-popup-content-wrapper {
          background-color: #281e1b !important; color: white !important;
          border: 1px solid #3a2c27 !important; border-radius: 12px !important;
          box-shadow: 0 8px 32px rgba(0,0,0,0.6) !important;
        }
        .leaflet-popup-tip { background-color: #281e1b !important; }
        .leaflet-popup-close-button { color: #bca39a !important; }
        .leaflet-popup-content { margin: 10px 14px !important; }
      `}</style>

      {/* ÔöÇÔöÇ Real Leaflet Map ÔöÇÔöÇ */}
      <div className="absolute inset-0 z-0">
        <MapContainer center={DEFAULT_CENTER} zoom={13} zoomControl={false} style={{ width: '100%', height: '100%' }}>
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
          />
          <MapController flyTarget={flyTarget} zoomCmd={zoomCmd} />

          {/* Pickup ÔåÆ Dropoff route */}
          {routePositions.length >= 2 && (
            <Polyline positions={routePositions} pathOptions={polylineOpts} />
          )}

          {/* Vehicle ÔåÆ Pickup approach route (dashed blue) */}
          {approachRoute.length >= 2 && (
            <Polyline
              positions={approachRoute}
              pathOptions={{ color: '#38bdf8', weight: 4, opacity: 0.8, dashArray: '10, 8', lineCap: 'round' }}
            />
          )}

          {/* Pickup marker */}
          <Marker position={[activeRoute.pickup.lat, activeRoute.pickup.lng]} icon={pickupIcon}>
            <Popup>
              <div className="text-sm">
                <div className="font-bold text-orange-400 mb-1">­ƒôª Pickup</div>
                <div className="font-semibold">{activeRoute.pickup.name}</div>
                <div className="text-gray-400 text-xs mt-0.5">{activeRoute.pickup.address}</div>
              </div>
            </Popup>
          </Marker>

          {/* Dropoff marker */}
          <Marker position={[activeRoute.dropoff.lat, activeRoute.dropoff.lng]} icon={dropoffIcon}>
            <Popup>
              <div className="text-sm">
                <div className="font-bold text-green-400 mb-1">­ƒÅá Dropoff</div>
                <div className="font-semibold">{activeRoute.dropoff.name}</div>
                <div className="text-gray-400 text-xs mt-0.5">{activeRoute.dropoff.address}</div>
              </div>
            </Popup>
          </Marker>

          {/* Live delivery tracker (pulsing truck) */}
          {trackerPos && (
            <Marker position={trackerPos} icon={truckIcon}>
              <Popup>
                <div className="text-sm">
                  <div className="font-bold text-orange-400 mb-1">­ƒÜÜ Delivery Guy</div>
                  <div className="text-gray-300">Speed: <span className="font-bold text-white">{displaySpeed} km/h</span></div>
                  {routeDistance && (
                    <div className="text-gray-300">Route: <span className="font-bold text-white">{distKm} km</span></div>
                  )}
                  <div className="text-gray-400 text-xs mt-1">Live GPS ┬À updating every second</div>
                </div>
              </Popup>
            </Marker>
          )}

          <MapResizer />
        </MapContainer>
      </div>

      {/* ÔöÇÔöÇ Search bar ÔöÇÔöÇ */}
      <div className="absolute top-4 left-4 right-4 md:w-96 z-10">
        <div className="flex w-full items-center rounded-xl bg-[#281e1b]/95 backdrop-blur-sm shadow-lg border border-[#3a2c27] h-12 overflow-hidden">
          <div className="flex items-center justify-center pl-4 pr-2 text-[#bca39a]">
            <span className="material-symbols-outlined">search</span>
          </div>
          <input
            type="text"
            className="w-full bg-transparent border-none text-white outline-none placeholder:text-[#bca39a] focus:ring-0 text-sm font-medium h-full"
            placeholder="Search location or route ID"
          />
        </div>
      </div>

      {/* ÔöÇÔöÇ Route info strip (distance / ETA / speed) ÔöÇÔöÇ */}
      <div className="absolute top-20 left-4 z-10 flex flex-col gap-2">
        {/* Distance + ETA pill */}
        <div className="flex items-center gap-2">
          {routeDistance && (
            <div className="flex items-center gap-1.5 bg-[#281e1b]/95 backdrop-blur-sm border border-[#3a2c27] rounded-full px-3 py-1.5 shadow-lg">
              <span className="material-symbols-outlined text-orange-400 text-[16px]">route</span>
              <span className="text-white text-xs font-bold">{distKm} km</span>
              <span className="text-[#bca39a] text-[10px]">┬À</span>
              <span className="text-[#bca39a] text-xs">{fmtDur(routeDuration)} ETA</span>
            </div>
          )}
          {routeLoading && (
            <div className="flex items-center gap-1.5 bg-[#281e1b]/95 backdrop-blur-sm border border-[#3a2c27] rounded-full px-3 py-1.5">
              <span className="material-symbols-outlined text-orange-400 text-[16px] animate-spin">refresh</span>
              <span className="text-[#bca39a] text-xs">Calculating routeÔÇª</span>
            </div>
          )}
        </div>

        {/* Live speed gauge (only when tracking) */}
        {tracking && (
          <div className="flex items-center gap-2 bg-[#281e1b]/95 backdrop-blur-sm border border-orange-500/40 rounded-full px-3 py-1.5 shadow-lg">
            <span className="size-2 rounded-full bg-orange-500 animate-pulse" />
            <span className="text-white text-sm font-black">{displaySpeed}</span>
            <span className="text-orange-400 text-[10px] font-bold uppercase tracking-wider">km/h</span>
          </div>
        )}
      </div>

      {/* ÔöÇÔöÇ Zoom + Locate + Track controls ÔöÇÔöÇ */}
      <div className="absolute bottom-32 md:bottom-8 right-4 md:right-8 flex flex-col gap-2 z-10">
        <div className="flex flex-col rounded-lg bg-[#281e1b]/95 backdrop-blur-sm shadow-lg border border-[#3a2c27] overflow-hidden">
          <button onClick={() => { setZoomCmd('in');  setTimeout(() => setZoomCmd(null), 150); }} className="p-2 hover:bg-[#3a2c27] text-white border-b border-[#3a2c27] transition-colors">
            <span className="material-symbols-outlined block">add</span>
          </button>
          <button onClick={() => { setZoomCmd('out'); setTimeout(() => setZoomCmd(null), 150); }} className="p-2 hover:bg-[#3a2c27] text-white transition-colors">
            <span className="material-symbols-outlined block">remove</span>
          </button>
        </div>

        {/* Locate Me */}
        <button
          onClick={handleLocateMe}
          disabled={locating}
          className={`p-2 rounded-lg text-white shadow-lg transition-all flex items-center justify-center
            ${locating ? 'bg-primary/50 cursor-wait animate-pulse' : 'bg-primary hover:bg-[#e55a2b] shadow-primary/20'}`}
          title="Locate Me"
        >
          <span className="material-symbols-outlined">{locating ? 'gps_not_fixed' : 'my_location'}</span>
        </button>

        {/* Start / Stop Live Tracker */}
        <button
          onClick={tracking ? stopTracking : startTracking}
          className={`p-2 rounded-lg text-white shadow-lg transition-all flex items-center justify-center
            ${tracking ? 'bg-red-500 hover:bg-red-600 shadow-red-500/30 animate-pulse' : 'bg-[#281e1b] border border-[#3a2c27] hover:bg-[#3a2c27]'}`}
          title={tracking ? 'Stop Live Tracking' : 'Start Live Tracking'}
        >
          <span className="material-symbols-outlined">{tracking ? 'stop_circle' : 'radio_button_checked'}</span>
        </button>
      </div>

      {/* ÔöÇÔöÇ Active Delivery Card ÔöÇÔöÇ */}
      {/* On mobile: compact pill, tap to expand. On desktop: always full card */}
      <MobileDeliveryCard
        isLoading={isLoading}
        activeRoute={activeRoute}
        distKm={distKm}
        routeDuration={routeDuration}
        displaySpeed={displaySpeed}
        tracking={tracking}
        startTracking={startTracking}
        stopTracking={stopTracking}
        fmtDur={fmtDur}
      />
    </div>
  );
}

import { useEffect, useState, useMemo } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import useListingStore from '../store/listingStore'
import useAuthStore from '../store/authStore'
import useRequestStore from '../store/requestStore'
import { toast } from 'react-hot-toast'

const DEFAULT_IMG = 'https://lh3.googleusercontent.com/aida-public/AB6AXuAUNyGSEU1fovxDPHC5CW9NhKOYvP4Qc8wkDwNYtJiEHhCYU1uZAVGRQbZ9ReoqT2iaTASE3ByNloa9kM6ASlSh4yv1ffZxCNrDi3aoYTaXKUeTtHc9EjnjBC6Ue_NNZ29EjnU8h97PuclaWAlglX_Vs0vYfNU6B1DSBL9RRFKGWXI9BzfBwSeL65rprr7kyaqr-lBT-8_y3D3L2uHQWKm_CXT4WagxYhJtSDYRuGZIQlHwclRgIslQO7X1U2N71ON6oRlsJ_X3sQ'

export default function ListingDetailsPage() {
  const { id } = useParams()
  const navigate = useNavigate()
  
  const user = useAuthStore(state => state.user)
  const listings = useListingStore(state => state.listings)
  const fetchListings = useListingStore(state => state.fetchListings)
  const isLoadingListings = useListingStore(state => state.isLoading)

  const createRequest = useRequestStore(state => state.createRequest)
  const isRequesting = useRequestStore(state => state.isLoading)

  const [localListing, setLocalListing] = useState(null)

  useEffect(() => {
    // If listings are empty, we might have arrived here directly. Fetch them.
    if (listings.length === 0) {
      fetchListings()
    }
  }, [listings.length, fetchListings])

  useEffect(() => {
    // Find the listing from store
    const found = listings.find(l => l.$id === id)
    if (found) setLocalListing(found)
  }, [id, listings])

  const handleRequestFood = async () => {
    if (!user) {
      toast.error('Please login to request food')
      navigate('/login')
      return
    }
    try {
      await createRequest({
        listingId: localListing.$id,
        receiverId: user.$id,
        receiverName: user.name,
      })
      toast.success('Food requested successfully!')
      navigate('/community')
    } catch (err) {
      toast.error(err.message || 'Failed to request food')
    }
  }

  if (isLoadingListings && !localListing) {
    return (
      <div className="flex-1 flex items-center justify-center bg-[#181210] min-h-screen">
        <span className="material-symbols-outlined animate-spin text-primary text-4xl">refresh</span>
      </div>
    )
  }

  if (!localListing) {
    return (
      <div className="flex-1 p-4 md:p-8 flex flex-col items-center justify-center bg-[#181210] min-h-screen text-center">
        <span className="material-symbols-outlined text-6xl text-[#bca39a] mb-4">search_off</span>
        <h1 className="text-2xl font-bold text-white mb-2">Listing Not Found</h1>
        <p className="text-[#bca39a] mb-6">The food listing you are looking for might have been removed or picked up.</p>
        <button onClick={() => navigate('/community')} className="px-6 py-2 bg-[#23140f] border border-[#3a2c27] text-white rounded-lg hover:border-primary transition-colors">
          Back to Feed
        </button>
      </div>
    )
  }

  // Formatting helpers
  const expiryDate = localListing.bestBefore ? new Date(localListing.bestBefore) : null
  const isExpired = expiryDate && expiryDate < new Date()
  
  return (
    <div className="flex-1 p-4 md:p-6 lg:p-8 max-h-screen overflow-y-auto bg-[#181210]">
      <div className="max-w-4xl mx-auto xl:px-8">
        
        {/* Top Action Bar */}
        <div className="flex items-center justify-between mb-6 sticky top-0 bg-[#181210]/90 backdrop-blur-md z-10 py-2 border-b border-[#3a2c27]">
          <button 
            onClick={() => navigate(-1)} 
            className="flex items-center gap-2 text-[#bca39a] hover:text-white transition-colors p-2 rounded-lg hover:bg-[#23140f]"
          >
            <span className="material-symbols-outlined">arrow_back</span>
            <span className="font-medium">Back</span>
          </button>
          
          <div className="flex gap-2">
            <button className="flex items-center gap-2 text-[#bca39a] hover:text-white transition-colors p-2 rounded-lg hover:bg-[#23140f]">
              <span className="material-symbols-outlined">share</span>
            </button>
            <button className="flex items-center gap-2 text-[#bca39a] hover:text-white transition-colors p-2 rounded-lg hover:bg-[#23140f]">
              <span className="material-symbols-outlined">flag</span>
            </button>
          </div>
        </div>

        {/* Main Content Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative">
          
          {/* Left Column: Image & Sticky Action */}
          <div className="space-y-6">
            <div className="aspect-square w-full rounded-2xl overflow-hidden border border-[#3a2c27] bg-[#23140f] relative group shadow-2xl">
              <img 
                src={localListing.imageUrl || DEFAULT_IMG} 
                alt={localListing.title} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
              />
              <div className="absolute top-4 left-4 bg-black/60 backdrop-blur-md text-white px-3 py-1 rounded-full text-xs font-bold border border-white/10 shadow-lg">
                {localListing.category}
              </div>
            </div>

            {/* Desktop Action Box (Sticky) */}
            <div className="hidden md:block sticky top-24 bg-[#23140f] border border-[#3a2c27] rounded-2xl p-6 shadow-xl space-y-4">
              <h3 className="font-bold text-white text-lg border-b border-[#3a2c27] pb-3 mb-3">Ready to collect?</h3>
              {localListing.status !== 'Active' || isExpired ? (
                <div className="bg-red-900/20 border border-red-900/50 text-red-400 p-4 rounded-xl flex items-start gap-3">
                  <span className="material-symbols-outlined text-lg">error</span>
                  <div>
                    <p className="font-bold text-sm">Not Available</p>
                    <p className="text-xs opacity-80 mt-1">This listing is {isExpired ? 'expired' : localListing.status.toLowerCase()}.</p>
                  </div>
                </div>
              ) : (
                <button 
                  onClick={handleRequestFood}
                  disabled={isRequesting || user?.$id === localListing.donorId}
                  className={`w-full py-4 rounded-xl font-bold text-white flex items-center justify-center gap-2 transition-all shadow-lg ${
                    user?.$id === localListing.donorId
                      ? 'bg-[#3a2c27] cursor-not-allowed opacity-50' 
                      : 'bg-primary hover:bg-orange-600 shadow-primary/20 hover:scale-[1.02]'
                  }`}
                >
                  {isRequesting ? (
                    <span className="material-symbols-outlined animate-spin">refresh</span>
                  ) : (
                    <span className="material-symbols-outlined">volunteer_activism</span>
                  )}
                  {user?.$id === localListing.donorId ? "This is your listing" : "Request This Food"}
                </button>
              )}
              {user?.$id !== localListing.donorId && localListing.status === 'Active' && !isExpired && (
                 <p className="text-xs text-center text-[#bca39a]">The donor will be notified instantly.</p>
              )}
            </div>
          </div>

          {/* Right Column: Details */}
          <div className="space-y-8 pb-32 md:pb-0">
            {/* Header Info */}
            <div>
              <div className="flex items-center gap-3 mb-3">
                <span className={`px-3 py-1 text-xs font-bold rounded-full border ${
                  localListing.diet === 'VEG' ? 'bg-green-900/30 text-green-400 border-green-700/50' :
                  localListing.diet === 'VEGAN' ? 'bg-yellow-900/30 text-yellow-400 border-yellow-700/50' :
                  localListing.diet === 'NON-VEG' ? 'bg-red-900/30 text-red-400 border-red-700/50' :
                  'bg-[#3a2c27] text-[#bca39a] border-[#3a2c27]'
                }`}>
                  {localListing.diet || 'Unknown Diet'}
                </span>
                
                {isExpired && (
                   <span className="px-3 py-1 bg-red-900/30 text-red-400 border border-red-700/50 font-bold text-xs rounded-full flex items-center gap-1">
                     <span className="material-symbols-outlined text-[14px]">warning</span> Expired
                   </span>
                )}
              </div>
              
              <h1 className="text-3xl md:text-4xl font-extrabold text-white leading-tight mb-2">
                {localListing.title}
              </h1>
              <p className="text-lg text-[#bca39a] flex items-center gap-2">
                 <span className="material-symbols-outlined text-[20px] text-primary">restaurant_menu</span>
                 Approx. {localListing.quantity} Servings Available
              </p>
            </div>

            {/* Quick Stats Grid */}
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-[#23140f] border border-[#3a2c27] rounded-xl p-4">
                <p className="text-xs text-[#bca39a] mb-1 font-medium flex items-center gap-1.5"><span className="material-symbols-outlined text-[14px]">schedule</span> Best Before</p>
                <p className={`font-bold ${isExpired ? 'text-red-400' : 'text-white'}`}>
                  {expiryDate ? expiryDate.toLocaleString('en-US', {
                      month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit'
                  }) : 'No expiry set'}
                </p>
              </div>
              <div className="bg-[#23140f] border border-[#3a2c27] rounded-xl p-4">
                <p className="text-xs text-[#bca39a] mb-1 font-medium flex items-center gap-1.5"><span className="material-symbols-outlined text-[14px]">category</span> Category</p>
                <p className="font-bold text-white">{localListing.category}</p>
              </div>
            </div>

            {/* Donor Info Box */}
            <div className="bg-gradient-to-br from-[#2a1d18] to-[#23140f] border border-[#3a2c27] rounded-xl p-5 shadow-lg relative overflow-hidden">
               <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full blur-2xl transform translate-x-10 -translate-y-10" />
               <h3 className="text-sm font-bold text-[#bca39a] uppercase tracking-wider mb-4 flex items-center gap-2">
                 <span className="material-symbols-outlined text-[18px]">account_circle</span> Donor Details
               </h3>
               
               <div className="flex items-center gap-4 mb-4">
                 <div className="size-12 rounded-full bg-gradient-to-br from-primary to-orange-700 flex items-center justify-center font-bold text-white text-xl shadow-lg shadow-primary/20">
                    {localListing.donorName?.charAt(0).toUpperCase() || '?'}
                 </div>
                 <div>
                   <p className="font-bold text-white text-lg">{localListing.donorName}</p>
                   <p className="text-sm text-[#bca39a]">Community Donor</p>
                 </div>
               </div>

               {localListing.address && (
                 <div className="flex items-start gap-3 pt-4 border-t border-[#3a2c27]/50 mt-4">
                    <span className="material-symbols-outlined text-[#bca39a] mt-0.5">location_on</span>
                    <div>
                      <p className="text-sm font-medium text-white mb-0.5">Pickup Location</p>
                      <p className="text-sm text-[#bca39a] leading-relaxed">{localListing.address}</p>
                    </div>
                 </div>
               )}
            </div>

            {/* Ingredients Section (Only if provided) */}
            {localListing.ingredients && (
              <div className="space-y-3">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                  <span className="material-symbols-outlined text-primary">eco</span> Ingredients
                </h3>
                <div className="bg-[#23140f] border border-[#3a2c27] rounded-xl p-5">
                  <p className="text-[#bca39a] text-sm leading-relaxed whitespace-pre-wrap">
                    {localListing.ingredients}
                  </p>
                </div>
              </div>
            )}

            {/* Guidelines */}
            <div className="space-y-3">
              <h3 className="text-xl font-bold text-white flex items-center gap-2">
                <span className="material-symbols-outlined text-primary">health_and_safety</span> Safety Guidelines
              </h3>
              <ul className="text-sm text-[#bca39a] space-y-2 bg-[#23140f] border border-[#3a2c27] p-5 rounded-xl">
                 <li className="flex gap-2 items-start"><span className="material-symbols-outlined text-[18px] text-green-500 shrink-0">check_circle</span> Please check the condition of the food visually and by smell before consuming.</li>
                 <li className="flex gap-2 items-start"><span className="material-symbols-outlined text-[18px] text-green-500 shrink-0">check_circle</span> Food should be consumed as close to the pickup time as possible.</li>
                 <li className="flex gap-2 items-start"><span className="material-symbols-outlined text-[18px] text-green-500 shrink-0">check_circle</span> Reheat cooked meals to a safe temperature before eating.</li>
              </ul>
            </div>

          </div>
        </div>
      </div>

      {/* Mobile Sticky Action Bar */}
      <div className="md:hidden fixed bottom-16 sm:bottom-0 left-0 right-0 bg-[#23140f]/95 backdrop-blur-xl border-t border-[#3a2c27] p-4 z-40 pb-[calc(1rem+env(safe-area-inset-bottom))]">
          {localListing.status !== 'Active' || isExpired ? (
            <button disabled className="w-full py-3.5 rounded-xl font-bold text-red-300 bg-red-900/30 flex items-center justify-center gap-2">
              <span className="material-symbols-outlined">error</span> Not Available
            </button>
          ) : (
            <button 
              onClick={handleRequestFood}
              disabled={isRequesting || user?.$id === localListing.donorId}
              className={`w-full py-3.5 rounded-xl font-bold text-white flex items-center justify-center gap-2 shadow-lg ${
                user?.$id === localListing.donorId
                  ? 'bg-[#3a2c27] cursor-not-allowed opacity-50' 
                  : 'bg-primary shadow-primary/20 hover:bg-orange-600'
              }`}
            >
              {isRequesting ? (
                <span className="material-symbols-outlined animate-spin">refresh</span>
              ) : (
                <span className="material-symbols-outlined">volunteer_activism</span>
              )}
              {user?.$id === localListing.donorId ? "This is your listing" : "Request This Food"}
            </button>
          )}
      </div>
    
    </div>
  )
}
